                            fontSize = 13.sp
                        )
                    }
                }
            }

            Spacer(modifier = Modifier.height(16.dp))

            // Task List
            uiState.displayedTasks.forEach { task ->
                TaskCard(task)
                Spacer(modifier = Modifier.height(12.dp))
            }

            Spacer(modifier = Modifier.height(60.dp)) // padding for FAB
        }
    }
}

@Composable
fun TaskCard(task: TaskItemUi) {
    val isCompleted = task.status == "COMPLETED"
    val chipBgColor = if (isCompleted) Color(0xFFF0FDF4) else Color(0xFFEFF6FF)
    val chipTextColor = if (isCompleted) Color(0xFF16A34A) else Color(0xFF1D4ED8)
    val titleColor = if (isCompleted) Color(0xFF94A3B8) else Color(0xFF0F172A)
    val descColor = if (isCompleted) Color(0xFF94A3B8) else Color(0xFF475569)

    Card(
        colors = CardDefaults.cardColors(containerColor = Color.White),
        shape = RoundedCornerShape(12.dp),
        elevation = CardDefaults.cardElevation(defaultElevation = 0.dp),
        modifier = Modifier.fillMaxWidth()
    ) {
        Row(modifier = Modifier.height(IntrinsicSize.Min)) {
            // Left color bar
            if (!isCompleted) {
                val barColor = if (task.isDueSoon) Color(0xFFDC2626) else Color(0xFFB45309)
                Box(
                    modifier = Modifier
                        .fillMaxHeight()
                        .width(4.dp)
                        .padding(vertical = 16.dp)
                        .background(barColor, RoundedCornerShape(topEnd = 4.dp, bottomEnd = 4.dp))
                )
            } else {
                Spacer(modifier = Modifier.width(4.dp))
            }

            Column(modifier = Modifier.padding(16.dp).weight(1f)) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.Top
                ) {
                    Text(
                        text = task.title,
                        color = titleColor,
                        fontSize = 16.sp,
                        fontWeight = FontWeight.Bold,
                        textDecoration = if (isCompleted) TextDecoration.LineThrough else null,
                        modifier = Modifier.weight(1f)
                    )
                    Spacer(modifier = Modifier.width(8.dp))
                    Surface(
                        color = chipBgColor,
                        shape = RoundedCornerShape(4.dp)
                    ) {
                        Text(
                            text = task.status,
                            color = chipTextColor,
                            fontSize = 9.sp,
                            fontWeight = FontWeight.Black,
                            modifier = Modifier.padding(horizontal = 6.dp, vertical = 3.dp),
                            letterSpacing = 0.5.sp
                        )
                    }
                }
                Spacer(modifier = Modifier.height(8.dp))
                Text(
                    text = task.description,
                    color = descColor,
                    fontSize = 13.sp,
                    lineHeight = 18.sp,
                    textDecoration = if (isCompleted) TextDecoration.LineThrough else null
                )
                Spacer(modifier = Modifier.height(16.dp))
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.End,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    if (task.dueText != null && !isCompleted) {
                        if (task.isDueSoon) {
                            Text(
                                "!",
                                color = Color(0xFFDC2626),
                                fontWeight = FontWeight.Bold,
                                fontSize = 14.sp
                            )
                            Spacer(modifier = Modifier.width(4.dp))
                        }
                        Text(
                            text = task.dueText ?: "",
                            color = if (task.isDueSoon) Color(0xFFDC2626) else Color(0xFFB45309),
                            fontSize = 10.sp,
                            fontWeight = FontWeight.Black,
                            letterSpacing = 0.5.sp
                        )
                        Spacer(modifier = Modifier.width(16.dp))
                    }

                    if (isCompleted) {
                        Icon(
                            imageVector = Icons.Outlined.CheckCircle,
                            contentDescription = null,
                            tint = Color(0xFF94A3B8),
                            modifier = Modifier.size(14.dp)
                        )
                    } else {
                        Icon(
                            imageVector = Icons.Outlined.CalendarToday,
                            contentDescription = null,
                            tint = Color(0xFF64748B),
                            modifier = Modifier.size(14.dp)
                        )
                    }
                    Spacer(modifier = Modifier.width(4.dp))
                    Text(
                        text = task.dateText,
                        color = if (isCompleted) Color(0xFF94A3B8) else Color(0xFF64748B),
                        fontSize = 12.sp,
                        fontWeight = FontWeight.SemiBold
                    )
                }
            }
        }
    }
}

package com.example.minorapp.data.auth

import com.example.minorapp.domain.model.UserRole
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import org.json.JSONObject
import java.io.IOException
import java.net.HttpURLConnection
import java.net.URL

sealed class AuthResult {
    data class Success(
        val accessToken: String,
        val refreshToken: String,
        val userId: Long,
        val email: String,
        val role: UserRole,
        val username: String?,
        val branch: String?,
        val batch: String?
    ) : AuthResult()

    data class Failure(val message: String) : AuthResult()
}

class AuthRepository(private val baseUrl: String) {
    suspend fun authenticate(
        email: String,
        password: String
    ): AuthResult = withContext(Dispatchers.IO) {
        var connection: HttpURLConnection? = null

        try {
            val normalizedBaseUrl = if (baseUrl.endsWith("/")) baseUrl else "$baseUrl/"
            val loginUrl = URL("${normalizedBaseUrl}${AuthConfig.AUTH_LOGIN_PATH}")

            connection = (loginUrl.openConnection() as HttpURLConnection).apply {
                requestMethod = "POST"
                connectTimeout = 10_000
                readTimeout = 10_000
                doOutput = true
                setRequestProperty("Content-Type", "application/json")
                setRequestProperty("Accept", "application/json")
            }

            val payload = JSONObject()
                .put("email", email)
                .put("password", password)
                .toString()

            connection.outputStream.use { output ->
                output.write(payload.toByteArray(Charsets.UTF_8))
                output.flush()
            }

            when (val statusCode = connection.responseCode) {
                in 200..299 -> parseSuccessResponse(connection)
                401 -> AuthResult.Failure("Invalid email or security key.")
                else -> AuthResult.Failure("Authentication failed ($statusCode).")
            }
        } catch (_: IOException) {
            AuthResult.Failure("Unable to reach server. Check connection and try again.")
        } catch (_: Exception) {
            AuthResult.Failure("Authentication service is currently unavailable.")
        } finally {
            connection?.disconnect()
        }
    }

    private fun parseSuccessResponse(connection: HttpURLConnection): AuthResult {
        val responseBody = connection.inputStream.bufferedReader().use { it.readText() }
        val root = JSONObject(responseBody)

        val status = root.optString("status")
        if (status != AuthConfig.SUCCESS_STATUS) {
            val message = root.optString("message").ifBlank { "Authentication failed." }
            return AuthResult.Failure(message)
        }

        val data = root.optJSONObject("data") ?: return AuthResult.Failure("Malformed auth response.")
        val accessToken = data.optString("accessToken")
        val refreshToken = data.optString("refreshToken")
        val user = data.optJSONObject("user") ?: return AuthResult.Failure("Malformed auth response.")

        val userId = user.optLong("id", -1L)
        val userEmail = user.optString("email")
        val roleRaw = user.optString("role")
        val role = roleRaw.toUserRoleOrNull()
        val username = user.optFirstNonBlank("username", "name", "fullName", "displayName")
        val branch = user.optFirstNonBlank("branch", "department", "program", "major")
        val batch = user.optFirstNonBlank("batch", "classOf", "cohort", "year", "classSection")

        if (accessToken.isBlank() || refreshToken.isBlank() || userId <= 0L || userEmail.isBlank() || role == null) {
            return AuthResult.Failure("Malformed auth response.")
        }

        return AuthResult.Success(
            accessToken = accessToken,
            refreshToken = refreshToken,
            userId = userId,
            email = userEmail,
            role = role,
            username = username,
            branch = branch,
            batch = batch
        )
    }

    private fun String.toUserRoleOrNull(): UserRole? {
        return runCatching { UserRole.valueOf(this.uppercase()) }.getOrNull()
    }

    private fun JSONObject.optFirstNonBlank(vararg keys: String): String? {
        for (key in keys) {
            val value = optString(key).trim()
            if (value.isNotBlank()) return value
        }
        return null
    }
}

package com.example.minorapp.data.auth

import com.example.minorapp.domain.model.UserRole
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import org.json.JSONObject
import java.io.IOException
import java.net.HttpURLConnection
import java.net.URL

sealed class AuthResult {
    data class Success(
        val accessToken: String,
        val refreshToken: String,
        val userId: Long,
        val email: String,
        val role: UserRole,
        val username: String?,
        val branch: String?,
        val batch: String?
    ) : AuthResult()

    data class Failure(val message: String) : AuthResult()
}

class AuthRepository(private val baseUrl: String) {
    suspend fun authenticate(
        email: String,
        password: String,
        selectedRole: UserRole
    ): AuthResult = withContext(Dispatchers.IO) {
        var connection: HttpURLConnection? = null

        try {
            val normalizedBaseUrl = if (baseUrl.endsWith("/")) baseUrl else "$baseUrl/"
            val loginUrl = URL("${normalizedBaseUrl}${AuthConfig.AUTH_LOGIN_PATH}")

            connection = (loginUrl.openConnection() as HttpURLConnection).apply {
                requestMethod = "POST"
                connectTimeout = 10_000
                readTimeout = 10_000
                doOutput = true
                setRequestProperty("Content-Type", "application/json")
                setRequestProperty("Accept", "application/json")
            }

            val payload = JSONObject()
                .put("email", email)
                .put("password", password)
                .put("role", selectedRole.name)
                .toString()

            connection.outputStream.use { output ->
                output.write(payload.toByteArray(Charsets.UTF_8))
                output.flush()
            }

            when (val statusCode = connection.responseCode) {
                in 200..299 -> parseSuccessResponse(connection)
                401 -> AuthResult.Failure("Invalid email or security key.")
                403 -> AuthResult.Failure(readErrorMessage(connection, "Selected role does not match this account."))
                400 -> AuthResult.Failure(readErrorMessage(connection, "Invalid login request."))
                else -> AuthResult.Failure("Authentication failed ($statusCode).")
            }
        } catch (_: IOException) {
            AuthResult.Failure("Unable to reach server. Check connection and try again.")
        } catch (_: Exception) {
            AuthResult.Failure("Authentication service is currently unavailable.")
        } finally {
            connection?.disconnect()
        }
    }

    private fun readErrorMessage(connection: HttpURLConnection, fallback: String): String {
        return runCatching {
            val raw = connection.errorStream?.bufferedReader()?.use { it.readText() } ?: return fallback
            val root = JSONObject(raw)
            root.optString("message").ifBlank { fallback }
        }.getOrElse { fallback }
    }

    private fun parseSuccessResponse(connection: HttpURLConnection): AuthResult {
        val responseBody = connection.inputStream.bufferedReader().use { it.readText() }
        val root = JSONObject(responseBody)

        val status = root.optString("status")
        if (status != AuthConfig.SUCCESS_STATUS) {
            val message = root.optString("message").ifBlank { "Authentication failed." }
            return AuthResult.Failure(message)
        }

        val data = root.optJSONObject("data") ?: return AuthResult.Failure("Malformed auth response.")
        val accessToken = data.optString("accessToken")
        val refreshToken = data.optString("refreshToken")
        val user = data.optJSONObject("user") ?: return AuthResult.Failure("Malformed auth response.")

        val userId = user.optLong("id", -1L)
        val userEmail = user.optString("email")
        val roleRaw = user.optString("role")
        val role = roleRaw.toUserRoleOrNull()
        val username = user.optFirstNonBlank("username", "name", "fullName", "displayName")
        val branch = user.optFirstNonBlank("branch", "department", "program", "major")
        val batch = user.optFirstNonBlank("batch", "classOf", "cohort", "year", "classSection")

        if (accessToken.isBlank() || refreshToken.isBlank() || userId <= 0L || userEmail.isBlank() || role == null) {
            return AuthResult.Failure("Malformed auth response.")
        }

        return AuthResult.Success(
            accessToken = accessToken,
            refreshToken = refreshToken,
            userId = userId,
            email = userEmail,
            role = role,
            username = username,
            branch = branch,
            batch = batch
        )
    }

    private fun String.toUserRoleOrNull(): UserRole? {
        return runCatching { UserRole.valueOf(this.uppercase()) }.getOrNull()
    }

    private fun JSONObject.optFirstNonBlank(vararg keys: String): String? {
        for (key in keys) {
            val value = optString(key).trim()
            if (value.isNotBlank()) return value
        }
        return null
    }
}

package com.example.minorapp.data.session

import android.content.Context
import com.example.minorapp.domain.model.UserRole
import java.util.concurrent.TimeUnit

class SessionManager(context: Context) {
    private val prefs = context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE)
    private val rememberWindowMillis = TimeUnit.DAYS.toMillis(30)

    fun saveLogin(
        role: UserRole,
        rememberFor30Days: Boolean,
        accessToken: String,
        refreshToken: String,
        email: String,
        username: String? = null,
        branch: String? = null,
        batch: String? = null
    ) {
        val loginTime = System.currentTimeMillis()
        val resolvedUsername = username?.trim()?.takeIf { it.isNotBlank() }
            ?: deriveDisplayNameFromEmail(email)

        prefs.edit()
            .putBoolean(KEY_IS_LOGGED_IN, true)
            .putBoolean(KEY_REMEMBER_FOR_30_DAYS, rememberFor30Days)
            .putLong(KEY_LOGIN_TIME, loginTime)
            .putString(KEY_USER_ROLE, role.name)
            .putString(KEY_ACCESS_TOKEN, accessToken)
            .putString(KEY_REFRESH_TOKEN, refreshToken)
            .putString(KEY_EMAIL, email)
            .apply()

        saveUsernameForRole(role, resolvedUsername)
        saveBranch(branch)
        saveBatch(batch)
    }

    fun shouldAutoLogin(nowMillis: Long = System.currentTimeMillis()): Boolean {
        val isLoggedIn = prefs.getBoolean(KEY_IS_LOGGED_IN, false)
        val rememberFor30Days = prefs.getBoolean(KEY_REMEMBER_FOR_30_DAYS, false)
        val loginTime = prefs.getLong(KEY_LOGIN_TIME, 0L)

        if (loginTime <= 0L) return false

        return isLoggedIn && rememberFor30Days && (nowMillis - loginTime) <= rememberWindowMillis
    }

    fun getSavedRole(): UserRole {
        val roleName = prefs.getString(KEY_USER_ROLE, UserRole.STUDENT.name)
        return UserRole.valueOf(roleName ?: UserRole.STUDENT.name)
    }

    fun clearSession() {
        prefs.edit().clear().apply()
    }

    fun getAccessToken(): String? = prefs.getString(KEY_ACCESS_TOKEN, null)

    fun getRefreshToken(): String? = prefs.getString(KEY_REFRESH_TOKEN, null)

    fun getSavedEmail(): String? = prefs.getString(KEY_EMAIL, null)

    fun saveProfileImageUri(uri: String?) {
        if (uri == null) {
            prefs.edit().remove(KEY_PROFILE_IMAGE_URI).apply()
        } else {
            prefs.edit().putString(KEY_PROFILE_IMAGE_URI, uri).apply()
        }
    }

    fun getProfileImageUri(): String? = prefs.getString(KEY_PROFILE_IMAGE_URI, null)

    fun saveUsername(username: String?) {
        saveUsernameForRole(getSavedRole(), username)
    }

    fun getSavedUsername(): String? = getSavedUsernameForRole(getSavedRole())

    fun saveUsernameForRole(role: UserRole, username: String?) {
        val key = when (role) {
            UserRole.STUDENT -> KEY_USERNAME_STUDENT
            UserRole.PROFESSOR -> KEY_USERNAME_PROFESSOR
        }
        val editor = prefs.edit()
        if (username.isNullOrBlank()) {
            editor.remove(key)
        } else {
            editor.putString(key, username)
        }
        // Keep legacy key updated for backwards compatibility with older snapshots.
        if (username.isNullOrBlank()) {
            editor.remove(KEY_USERNAME)
        } else {
            editor.putString(KEY_USERNAME, username)
        }
        editor.apply()
    }

    fun getSavedUsernameForRole(role: UserRole): String? {
        val key = when (role) {
            UserRole.STUDENT -> KEY_USERNAME_STUDENT
            UserRole.PROFESSOR -> KEY_USERNAME_PROFESSOR
        }
        return prefs.getString(key, null) ?: prefs.getString(KEY_USERNAME, null)
    }

    fun getPreferredDisplayName(role: UserRole): String? {
        val savedRoleName = getSavedUsernameForRole(role)?.trim()?.takeIf { it.isNotBlank() }
        if (savedRoleName != null) return savedRoleName
        return deriveDisplayNameFromEmail(getSavedEmail())
    }

    fun saveBranch(branch: String?) {
        if (branch.isNullOrBlank()) {
            prefs.edit().remove(KEY_BRANCH).apply()
        } else {
            prefs.edit().putString(KEY_BRANCH, branch).apply()
        }
    }

    fun getSavedBranch(): String? = prefs.getString(KEY_BRANCH, null)

    fun saveBatch(batch: String?) {
        if (batch.isNullOrBlank()) {
            prefs.edit().remove(KEY_BATCH).apply()
        } else {
            prefs.edit().putString(KEY_BATCH, batch).apply()
        }
    }

    fun getSavedBatch(): String? = prefs.getString(KEY_BATCH, null)

    fun saveStudentDashboardSnapshot(snapshotJson: String?) {
        if (snapshotJson.isNullOrBlank()) {
            prefs.edit().remove(KEY_STUDENT_DASHBOARD_SNAPSHOT).apply()
        } else {
            prefs.edit().putString(KEY_STUDENT_DASHBOARD_SNAPSHOT, snapshotJson).apply()
        }
    }

    fun getStudentDashboardSnapshot(): String? = prefs.getString(KEY_STUDENT_DASHBOARD_SNAPSHOT, null)

    fun saveAttendanceMonthlyInsightsSnapshot(snapshotJson: String?) {
        if (snapshotJson.isNullOrBlank()) {
            prefs.edit().remove(KEY_ATTENDANCE_MONTHLY_INSIGHTS_SNAPSHOT).apply()
        } else {
            prefs.edit().putString(KEY_ATTENDANCE_MONTHLY_INSIGHTS_SNAPSHOT, snapshotJson).apply()
        }
    }

    fun getAttendanceMonthlyInsightsSnapshot(): String? =
        prefs.getString(KEY_ATTENDANCE_MONTHLY_INSIGHTS_SNAPSHOT, null)

    fun saveAttendanceSemesterInsightsSnapshot(snapshotJson: String?) {
        if (snapshotJson.isNullOrBlank()) {
            prefs.edit().remove(KEY_ATTENDANCE_SEMESTER_INSIGHTS_SNAPSHOT).apply()
        } else {
            prefs.edit().putString(KEY_ATTENDANCE_SEMESTER_INSIGHTS_SNAPSHOT, snapshotJson).apply()
        }
    }

    fun getAttendanceSemesterInsightsSnapshot(): String? =
        prefs.getString(KEY_ATTENDANCE_SEMESTER_INSIGHTS_SNAPSHOT, null)

    fun saveTasksSubmissionSnapshot(snapshotJson: String?) {
        if (snapshotJson.isNullOrBlank()) {
            prefs.edit().remove(KEY_TASKS_SUBMISSION_SNAPSHOT).apply()
        } else {
            prefs.edit().putString(KEY_TASKS_SUBMISSION_SNAPSHOT, snapshotJson).apply()
        }
    }

    fun getTasksSubmissionSnapshot(): String? = prefs.getString(KEY_TASKS_SUBMISSION_SNAPSHOT, null)

    private fun deriveDisplayNameFromEmail(email: String?): String? {
        val localPart = email
            ?.substringBefore('@')
            ?.trim()
            ?.takeIf { it.isNotBlank() }
            ?: return null

        val words = localPart
            .split('.', '_', '-')
            .map { it.trim() }
            .filter { it.isNotBlank() }

        if (words.isEmpty()) return null

        return words.joinToString(" ") { token ->
            token.lowercase().replaceFirstChar { ch ->
                if (ch.isLowerCase()) ch.titlecase() else ch.toString()
            }
        }
    }

    companion object {
        private const val PREF_NAME = "mycampus_session"
        private const val KEY_IS_LOGGED_IN = "is_logged_in"
        private const val KEY_REMEMBER_FOR_30_DAYS = "remember_for_30_days"
        private const val KEY_LOGIN_TIME = "login_time"
        private const val KEY_USER_ROLE = "user_role"
        private const val KEY_ACCESS_TOKEN = "access_token"
        private const val KEY_REFRESH_TOKEN = "refresh_token"
        private const val KEY_EMAIL = "email"
        private const val KEY_PROFILE_IMAGE_URI = "profile_image_uri"
        private const val KEY_USERNAME = "username"
        private const val KEY_USERNAME_STUDENT = "username_student"
        private const val KEY_USERNAME_PROFESSOR = "username_professor"
        private const val KEY_BRANCH = "branch"
        private const val KEY_BATCH = "batch"
        private const val KEY_STUDENT_DASHBOARD_SNAPSHOT = "student_dashboard_snapshot"
        private const val KEY_ATTENDANCE_MONTHLY_INSIGHTS_SNAPSHOT = "attendance_monthly_insights_snapshot"
        private const val KEY_ATTENDANCE_SEMESTER_INSIGHTS_SNAPSHOT = "attendance_semester_insights_snapshot"
        private const val KEY_TASKS_SUBMISSION_SNAPSHOT = "tasks_submission_snapshot"
    }
}

package com.example.minorapp.data.session

import android.content.Context
import com.example.minorapp.domain.model.UserRole
import java.util.concurrent.TimeUnit

class SessionManager(context: Context) {
    private val prefs = context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE)
    private val rememberWindowMillis = TimeUnit.DAYS.toMillis(30)

    fun saveLogin(
        role: UserRole,
        rememberFor30Days: Boolean,
        accessToken: String,
        refreshToken: String,
        email: String,
        username: String? = null,
        branch: String? = null,
        batch: String? = null
    ) {
        val loginTime = System.currentTimeMillis()
        val resolvedUsername = username?.trim()?.takeIf { it.isNotBlank() }
            ?: deriveDisplayNameFromEmail(email)

        prefs.edit()
            .putBoolean(KEY_IS_LOGGED_IN, true)
            .putBoolean(KEY_REMEMBER_FOR_30_DAYS, rememberFor30Days)
            .putLong(KEY_LOGIN_TIME, loginTime)
            .putString(KEY_USER_ROLE, role.name)
            .putString(KEY_ACCESS_TOKEN, accessToken)
            .putString(KEY_REFRESH_TOKEN, refreshToken)
            .putString(KEY_EMAIL, email)
            .apply()

        saveUsernameForRole(role, resolvedUsername)
        saveBranch(branch)
        saveBatch(batch)
    }

    fun shouldAutoLogin(nowMillis: Long = System.currentTimeMillis()): Boolean {
        val isLoggedIn = prefs.getBoolean(KEY_IS_LOGGED_IN, false)
        val rememberFor30Days = prefs.getBoolean(KEY_REMEMBER_FOR_30_DAYS, false)
        val loginTime = prefs.getLong(KEY_LOGIN_TIME, 0L)

        if (loginTime <= 0L) return false

        return isLoggedIn && rememberFor30Days && (nowMillis - loginTime) <= rememberWindowMillis
    }

    fun getSavedRole(): UserRole {
        val roleName = prefs.getString(KEY_USER_ROLE, UserRole.STUDENT.name)
        return UserRole.valueOf(roleName ?: UserRole.STUDENT.name)
    }

    fun clearSession() {
        prefs.edit().clear().apply()
    }

    fun getAccessToken(): String? = prefs.getString(KEY_ACCESS_TOKEN, null)

    fun getRefreshToken(): String? = prefs.getString(KEY_REFRESH_TOKEN, null)

    fun getSavedEmail(): String? = prefs.getString(KEY_EMAIL, null)

    fun saveProfileImageUri(uri: String?) {
        if (uri == null) {
            prefs.edit().remove(KEY_PROFILE_IMAGE_URI).apply()
        } else {
            prefs.edit().putString(KEY_PROFILE_IMAGE_URI, uri).apply()
        }
    }

    fun getProfileImageUri(): String? = prefs.getString(KEY_PROFILE_IMAGE_URI, null)

    fun saveUsername(username: String?) {
        saveUsernameForRole(getSavedRole(), username)
    }

    fun getSavedUsername(): String? = getSavedUsernameForRole(getSavedRole())

    fun saveUsernameForRole(role: UserRole, username: String?) {
        val key = when (role) {
            UserRole.STUDENT -> KEY_USERNAME_STUDENT
            UserRole.PROFESSOR -> KEY_USERNAME_PROFESSOR
        }
        val editor = prefs.edit()
        if (username.isNullOrBlank()) {
            editor.remove(key)
        } else {
            editor.putString(key, username)
        }
        // Keep legacy key updated for backwards compatibility with older snapshots.
        if (username.isNullOrBlank()) {
            editor.remove(KEY_USERNAME)
        } else {
            editor.putString(KEY_USERNAME, username)
        }
        editor.apply()
    }

    fun getSavedUsernameForRole(role: UserRole): String? {
        val key = when (role) {
            UserRole.STUDENT -> KEY_USERNAME_STUDENT
            UserRole.PROFESSOR -> KEY_USERNAME_PROFESSOR
        }
        return prefs.getString(key, null) ?: prefs.getString(KEY_USERNAME, null)
    }

    fun getPreferredDisplayName(role: UserRole): String? {
        val savedRoleName = getSavedUsernameForRole(role)?.trim()?.takeIf { it.isNotBlank() }
        if (savedRoleName != null) return savedRoleName
        return deriveDisplayNameFromEmail(getSavedEmail())
    }

    fun saveBranch(branch: String?) {
        if (branch.isNullOrBlank()) {
            prefs.edit().remove(KEY_BRANCH).apply()
        } else {
            prefs.edit().putString(KEY_BRANCH, branch).apply()
        }
    }

    fun getSavedBranch(): String? = prefs.getString(KEY_BRANCH, null)

    fun saveBatch(batch: String?) {
        if (batch.isNullOrBlank()) {
            prefs.edit().remove(KEY_BATCH).apply()
        } else {
            prefs.edit().putString(KEY_BATCH, batch).apply()
        }
    }

    fun getSavedBatch(): String? = prefs.getString(KEY_BATCH, null)

    fun saveStudentDashboardSnapshot(snapshotJson: String?) {
        if (snapshotJson.isNullOrBlank()) {
            prefs.edit().remove(KEY_STUDENT_DASHBOARD_SNAPSHOT).apply()
        } else {
            prefs.edit().putString(KEY_STUDENT_DASHBOARD_SNAPSHOT, snapshotJson).apply()
        }
    }

    fun getStudentDashboardSnapshot(): String? = prefs.getString(KEY_STUDENT_DASHBOARD_SNAPSHOT, null)

    fun saveAttendanceMonthlyInsightsSnapshot(snapshotJson: String?) {
        if (snapshotJson.isNullOrBlank()) {
            prefs.edit().remove(KEY_ATTENDANCE_MONTHLY_INSIGHTS_SNAPSHOT).apply()
        } else {
            prefs.edit().putString(KEY_ATTENDANCE_MONTHLY_INSIGHTS_SNAPSHOT, snapshotJson).apply()
        }
    }

    fun getAttendanceMonthlyInsightsSnapshot(): String? =
        prefs.getString(KEY_ATTENDANCE_MONTHLY_INSIGHTS_SNAPSHOT, null)

    fun saveAttendanceSemesterInsightsSnapshot(snapshotJson: String?) {
        if (snapshotJson.isNullOrBlank()) {
            prefs.edit().remove(KEY_ATTENDANCE_SEMESTER_INSIGHTS_SNAPSHOT).apply()
        } else {
            prefs.edit().putString(KEY_ATTENDANCE_SEMESTER_INSIGHTS_SNAPSHOT, snapshotJson).apply()
        }
    }

    fun getAttendanceSemesterInsightsSnapshot(): String? =
        prefs.getString(KEY_ATTENDANCE_SEMESTER_INSIGHTS_SNAPSHOT, null)

    fun saveTasksSubmissionSnapshot(snapshotJson: String?) {
        if (snapshotJson.isNullOrBlank()) {
            prefs.edit().remove(KEY_TASKS_SUBMISSION_SNAPSHOT).apply()
        } else {
            prefs.edit().putString(KEY_TASKS_SUBMISSION_SNAPSHOT, snapshotJson).apply()
        }
    }

    fun getTasksSubmissionSnapshot(): String? = prefs.getString(KEY_TASKS_SUBMISSION_SNAPSHOT, null)

    fun saveProfessorAttendanceHistorySnapshot(snapshotJson: String?) {
        val scopedKey = professorAttendanceHistorySnapshotKey()
        if (snapshotJson.isNullOrBlank()) {
            prefs.edit().remove(scopedKey).apply()
        } else {
            prefs.edit().putString(scopedKey, snapshotJson).apply()
        }
    }

    fun getProfessorAttendanceHistorySnapshot(): String? {
        val scopedKey = professorAttendanceHistorySnapshotKey()
        val scopedValue = prefs.getString(scopedKey, null)
        if (!scopedValue.isNullOrBlank()) {
            return scopedValue
        }

        // Backward compatibility for previously saved shared history.
        val legacyValue = prefs.getString(KEY_PROFESSOR_ATTENDANCE_HISTORY_SNAPSHOT, null)
        if (!legacyValue.isNullOrBlank() && scopedKey != KEY_PROFESSOR_ATTENDANCE_HISTORY_SNAPSHOT) {
            prefs.edit().putString(scopedKey, legacyValue).apply()
        }
        return legacyValue
    }

    private fun professorAttendanceHistorySnapshotKey(): String {
        val email = getSavedEmail().orEmpty().trim().lowercase()
        if (email.isBlank()) {
            return KEY_PROFESSOR_ATTENDANCE_HISTORY_SNAPSHOT
        }

        val normalized = email
            .replace(Regex("[^a-z0-9]"), "_")
            .replace(Regex("_+"), "_")
            .trim('_')

        return if (normalized.isBlank()) {
            KEY_PROFESSOR_ATTENDANCE_HISTORY_SNAPSHOT
        } else {
            "${KEY_PROFESSOR_ATTENDANCE_HISTORY_SNAPSHOT}_$normalized"
        }
    }

    private fun deriveDisplayNameFromEmail(email: String?): String? {
        val localPart = email
            ?.substringBefore('@')
            ?.trim()
            ?.takeIf { it.isNotBlank() }
            ?: return null

        val words = localPart
            .split('.', '_', '-')
            .map { it.trim() }
            .filter { it.isNotBlank() }

        if (words.isEmpty()) return null

        return words.joinToString(" ") { token ->
            token.lowercase().replaceFirstChar { ch ->
                if (ch.isLowerCase()) ch.titlecase() else ch.toString()
            }
        }
    }

    companion object {
        private const val PREF_NAME = "mycampus_session"
        private const val KEY_IS_LOGGED_IN = "is_logged_in"
        private const val KEY_REMEMBER_FOR_30_DAYS = "remember_for_30_days"
        private const val KEY_LOGIN_TIME = "login_time"
        private const val KEY_USER_ROLE = "user_role"
        private const val KEY_ACCESS_TOKEN = "access_token"
        private const val KEY_REFRESH_TOKEN = "refresh_token"
        private const val KEY_EMAIL = "email"
        private const val KEY_PROFILE_IMAGE_URI = "profile_image_uri"
        private const val KEY_USERNAME = "username"
        private const val KEY_USERNAME_STUDENT = "username_student"
        private const val KEY_USERNAME_PROFESSOR = "username_professor"
        private const val KEY_BRANCH = "branch"
        private const val KEY_BATCH = "batch"
        private const val KEY_STUDENT_DASHBOARD_SNAPSHOT = "student_dashboard_snapshot"
        private const val KEY_ATTENDANCE_MONTHLY_INSIGHTS_SNAPSHOT = "attendance_monthly_insights_snapshot"
        private const val KEY_ATTENDANCE_SEMESTER_INSIGHTS_SNAPSHOT = "attendance_semester_insights_snapshot"
        private const val KEY_TASKS_SUBMISSION_SNAPSHOT = "tasks_submission_snapshot"
        private const val KEY_PROFESSOR_ATTENDANCE_HISTORY_SNAPSHOT = "professor_attendance_history_snapshot"
    }
}

package com.example.minorapp.presentation.screen.attendance

import androidx.compose.runtime.Composable
import androidx.compose.runtime.LaunchedEffect
import androidx.lifecycle.viewmodel.compose.viewModel
import com.example.minorapp.data.session.SessionManager

@Composable
fun ProfessorAttendanceRoute(
    sessionManager: SessionManager,
    onNavigateToDashboard: () -> Unit,
    onNavigateToTasks: () -> Unit = {},
    onNavigateToSummary: () -> Unit = {},
    onProfileClick: () -> Unit = {},
    onLogoutClick: () -> Unit = {}
) {
    val viewModel: ProfessorAttendanceViewModel = viewModel(
        factory = ProfessorAttendanceViewModel.factory(sessionManager)
    )

    LaunchedEffect(viewModel.uiState.shouldForceReauth) {
        if (viewModel.uiState.shouldForceReauth) {
            viewModel.onForceReauthHandled()
            onLogoutClick()
        }
    }

    ProfessorAttendanceScreen(
        viewModel.uiState,
        viewModel::onStudentStatusChange,
        viewModel::onMarkAllPresent,
        viewModel::onModeSelected,
        viewModel::onCourseSelected,
        viewModel::onStartQrAttendance,
        onNavigateToDashboard,
        onNavigateToTasks,
        onNavigateToSummary,
        onProfileClick,
        onLogoutClick,
        { /* Handle manual submit later */ }
    )
}

