@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun ProfessorAttendanceScreen(
    uiState: ProfessorAttendanceUiState,
    onStudentStatusChange: (String, AttendanceStatus) -> Unit,
    onMarkAllPresent: () -> Unit,
    onModeSelected: (ProfessorAttendanceMode) -> Unit,
    onCourseSelected: (Long) -> Unit,
    onStartQrAttendance: () -> Unit,
    onNavigateToDashboard: () -> Unit,
    onNavigateToTasks: () -> Unit,
    onNavigateToSummary: () -> Unit,
    onProfileClick: () -> Unit,
    onLogoutClick: () -> Unit = {},
    onSubmitClick: () -> Unit = {}
) {
    var showHistoryDialog by remember { mutableStateOf(false) }

    val topBarSubjects = uiState.availableCourses.map { it.name }.ifEmpty {
        listOf(uiState.courseCode).filter { it.isNotBlank() }
    }

    Scaffold(
        topBar = {
            MyCampusTopBar(
                profileImageUri = uiState.profileImageUri,
                onProfileClick = onProfileClick,
                subjects = topBarSubjects,
                onLogoutClick = onLogoutClick
            )
        },
        bottomBar = {
            NavigationBar(containerColor = Color.White) {
                NavigationBarItem(
                    selected = false,
                    onClick = onNavigateToDashboard,
                    icon = { Icon(Icons.Default.Home, contentDescription = "Dashboard", tint = Color(0xFF94A3B8)) },
                    label = { Text("DASHBOARD", color = Color(0xFF94A3B8), fontWeight = FontWeight.Bold, fontSize = 10.sp) },
                    colors = NavigationBarItemDefaults.colors(indicatorColor = Color(0xFFF0F7FF))
                )
                NavigationBarItem(
                    selected = true,
                    onClick = {},
                    icon = { Icon(Icons.Outlined.BackHand, contentDescription = "Attendance", tint = Color(0xFF0265DC)) },
                    label = { Text("ATTENDANCE", color = Color(0xFF0265DC), fontWeight = FontWeight.Bold, fontSize = 10.sp) },
                    colors = NavigationBarItemDefaults.colors(indicatorColor = Color(0xFFF0F7FF))
                )
                NavigationBarItem(
                    selected = false,
                    onClick = onNavigateToTasks,
                    icon = { Icon(Icons.Outlined.Edit, contentDescription = "Tasks", tint = Color(0xFF94A3B8)) },
                    label = { Text("TASKS", color = Color(0xFF94A3B8), fontWeight = FontWeight.Bold, fontSize = 10.sp) },
                    colors = NavigationBarItemDefaults.colors(indicatorColor = Color(0xFFF0F7FF))
                )
                NavigationBarItem(
                    selected = false,
                    onClick = onNavigateToSummary,
                    icon = { Icon(Icons.Outlined.BarChart, contentDescription = "Summary", tint = Color(0xFF94A3B8)) },
                    label = { Text("SUMMARY", color = Color(0xFF94A3B8), fontWeight = FontWeight.Bold, fontSize = 10.sp) },
                    colors = NavigationBarItemDefaults.colors(indicatorColor = Color(0xFFF0F7FF))
                )
            }
        },
        containerColor = Color(0xFFF8FAFC)
    ) { innerPadding ->
        LazyColumn(
            modifier = Modifier.fillMaxSize().padding(innerPadding),
            contentPadding = PaddingValues(20.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            // Header Region
            item {
                Surface(shape = RoundedCornerShape(6.dp), color = Color(0xFFDBEAFE)) {
                    Text(
                        text = "COURSE SESSION",
                        color = Color(0xFF1E40AF),
                        fontWeight = FontWeight.Bold,
                        fontSize = 11.sp,
                        modifier = Modifier.padding(horizontal = 8.dp, vertical = 4.dp),
                        letterSpacing = 1.sp
                    )
                }
                Spacer(modifier = Modifier.height(12.dp))
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.End,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    IconButton(onClick = { showHistoryDialog = true }) {
                        Icon(
                            imageVector = Icons.Outlined.AccessTime,
                            contentDescription = "Attendance history",
                            tint = Color(0xFF1D4ED8)
                        )
                    }
                    Text(text = uiState.courseCode, fontSize = 36.sp, fontWeight = FontWeight.ExtraBold, color = Color(0xFF0F172A), lineHeight = 40.sp)
                }
                Spacer(modifier = Modifier.height(8.dp))
                Text(text = uiState.titleSubtitle, fontSize = 16.sp, color = Color(0xFF334155), lineHeight = 22.sp)
                Spacer(modifier = Modifier.height(6.dp))
                val subjectLabel = if (uiState.subjectCode.isNotBlank()) {
                    "${uiState.subjectName} (${uiState.subjectCode})"
                } else {
                    uiState.subjectName
                }
                Text(text = subjectLabel, fontSize = 14.sp, fontWeight = FontWeight.SemiBold, color = Color(0xFF1E3A8A))
                Spacer(modifier = Modifier.height(16.dp))
                Text(text = uiState.sessionDate, fontSize = 16.sp, fontWeight = FontWeight.Bold, color = Color(0xFF1D4ED8))
                Text(text = uiState.sessionTime, fontSize = 14.sp, color = Color(0xFF64748B))
            }

            // QR and Metric Cards
            item {
                QrAttendanceControlCard(
                    uiState = uiState,
                    onModeSelected = onModeSelected,
                    onCourseSelected = onCourseSelected,
                    onStartQrAttendance = onStartQrAttendance
                )
            }
            item { Spacer(modifier = Modifier.height(8.dp)) }
            item {
                Column(verticalArrangement = Arrangement.spacedBy(12.dp)) {
                    MetricRowCard("TOTAL ENROLLED", uiState.totalEnrolled.toString(), indicatorColor = Color(0xFF2563EB))
                    MetricRowCard("MARKED PRESENT", "${uiState.markedPresent}", " / ${uiState.totalEnrolled}", Color(0xFFD97706))
                    MetricRowCard("COMPLETION", "${uiState.completionPercent}%", indicatorColor = Color(0xFF94A3B8))
                }
            }

            // Sub-header Student Registry
            item { Spacer(modifier = Modifier.height(8.dp)) }
            item {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Text("Student Registry", fontSize = 20.sp, fontWeight = FontWeight.Bold, color = Color(0xFF0F172A))
                    Row(verticalAlignment = Alignment.CenterVertically, modifier = Modifier.clickable { onMarkAllPresent() }) {
                        Icon(Icons.Default.Check, contentDescription = null, tint = Color(0xFF2563EB), modifier = Modifier.size(16.dp))
                        Spacer(modifier = Modifier.width(4.dp))
                        Text("Mark All Present", color = Color(0xFF2563EB), fontWeight = FontWeight.SemiBold, fontSize = 14.sp)
                    }
                }
            }

            // List of Students
            items(uiState.students) { student ->
                StudentAttendanceItem(student = student, onStatusSelected = { onStudentStatusChange(student.studentId, it) })
            }

            // Submit Button for Manual Attendance
            if (uiState.attendanceMode == ProfessorAttendanceMode.MANUAL) {
                item {
                    Button(
                        onClick = onSubmitClick,
                        modifier = Modifier.fillMaxWidth().height(56.dp),
                        shape = RoundedCornerShape(12.dp),
                        colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF1D4ED8))
                    ) {
                        Text("Submit Attendance Record", fontWeight = FontWeight.Bold, fontSize = 16.sp, color = Color.White)
                    }
                }
            }

            item { Spacer(modifier = Modifier.height(12.dp)) }
        }

        if (showHistoryDialog) {
            AttendanceHistoryDialog(
                history = uiState.attendanceHistory,
                onDismiss = { showHistoryDialog = false }
            )
        }
    }
}

@Composable
private fun AttendanceHistoryDialog(
    history: List<AttendanceHistoryEntryUi>,
    onDismiss: () -> Unit
) {
    AlertDialog(
        onDismissRequest = onDismiss,
        confirmButton = {
            Button(onClick = onDismiss) {
                Text("Close")
            }
        },
        title = {
            Text(
                text = "Attendance History (Last 10)",
                fontWeight = FontWeight.Bold
            )
        },
        text = {
            if (history.isEmpty()) {
                Text("No attendance records yet.", color = Color(0xFF64748B))
            } else {
                Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                    history.forEach { item ->
                        Column {
                            Text(
                                text = "${item.courseName} • ${item.modeLabel}",
                                color = Color(0xFF0F172A),
                                fontWeight = FontWeight.SemiBold,
                                fontSize = 14.sp
                            )
                            Text(
                                text = item.recordedAtText,
                                color = Color(0xFF64748B),
                                fontSize = 12.sp
                            )
                        }
                    }
                }
            }
        }
    )
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
private fun QrAttendanceControlCard(
    uiState: ProfessorAttendanceUiState,
    onModeSelected: (ProfessorAttendanceMode) -> Unit,
    onCourseSelected: (Long) -> Unit,
    onStartQrAttendance: () -> Unit
) {
    var modeExpanded by remember { mutableStateOf(false) }
    var courseExpanded by remember { mutableStateOf(false) }

    Card(modifier = Modifier.fillMaxWidth(), colors = CardDefaults.cardColors(containerColor = Color.White), shape = RoundedCornerShape(12.dp)) {
        Column(modifier = Modifier.padding(14.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
            Text("Attendance Mode", fontWeight = FontWeight.Bold, color = Color(0xFF0F172A))

            ExposedDropdownMenuBox(expanded = modeExpanded, onExpandedChange = { modeExpanded = !modeExpanded }) {
                OutlinedTextField(
                    value = if (uiState.attendanceMode == ProfessorAttendanceMode.QR_CODE) "QR Code" else "Manual",
                    onValueChange = {},
                    readOnly = true,
                    trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(expanded = modeExpanded) },
                    modifier = Modifier.menuAnchor(MenuAnchorType.PrimaryNotEditable, enabled = true).fillMaxWidth()
                )
                DropdownMenu(expanded = modeExpanded, onDismissRequest = { modeExpanded = false }) {
                    DropdownMenuItem(text = { Text("Manual") }, onClick = { onModeSelected(ProfessorAttendanceMode.MANUAL); modeExpanded = false })
                    DropdownMenuItem(text = { Text("QR Code") }, onClick = { onModeSelected(ProfessorAttendanceMode.QR_CODE); modeExpanded = false })
                }
            }

            ExposedDropdownMenuBox(expanded = courseExpanded, onExpandedChange = { courseExpanded = !courseExpanded }) {
                val selectedCourse = uiState.availableCourses.firstOrNull { it.id == uiState.selectedCourseId }
                OutlinedTextField(
                    value = selectedCourse?.let { "${it.name} (${it.enrolledCount})" } ?: "Select Class",
                    onValueChange = {},
                    readOnly = true,
                    trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(expanded = courseExpanded) },
                    modifier = Modifier.menuAnchor(MenuAnchorType.PrimaryNotEditable, enabled = true).fillMaxWidth()
                )
                DropdownMenu(expanded = courseExpanded, onDismissRequest = { courseExpanded = false }) {
                    uiState.availableCourses.forEach { course ->
                        DropdownMenuItem(
                            text = { Text("${course.name} (${course.enrolledCount})") },
                            onClick = {
                                onCourseSelected(course.id)
                                courseExpanded = false
                            }
                        )
                    }
                }
            }

            if (uiState.attendanceMode == ProfessorAttendanceMode.QR_CODE) {
                Button(
                    onClick = onStartQrAttendance,
                    enabled = !uiState.isStartingQr && uiState.selectedCourseId > 0,
                    modifier = Modifier.fillMaxWidth(),
                    colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF2563EB))
                ) {
                    Text(if (uiState.isStartingQr) "Starting..." else "Start Attendance", color = Color.White)
                }

                uiState.qrSession?.let { session ->
                    Text("Session ${session.sessionId} • Expires in ${session.secondsRemaining}s", color = Color(0xFF1D4ED8), fontWeight = FontWeight.SemiBold, fontSize = 12.sp)
                    QrPayloadImage(payload = session.qrPayload)
                }

                if (uiState.qrSession == null && uiState.isQrAttendanceFinalized) {
                    Surface(
                        color = Color(0xFFECFDF3),
                        shape = RoundedCornerShape(999.dp)
                    ) {
                        Text(
                            text = "Finalized" + (uiState.qrFinalizedAtText?.let { " • $it" } ?: ""),
                            color = Color(0xFF027A48),
                            fontSize = 12.sp,
                            fontWeight = FontWeight.SemiBold,
                            modifier = Modifier.padding(horizontal = 10.dp, vertical = 6.dp)
                        )
                    }
                }

                if (!uiState.qrError.isNullOrBlank()) {
                    Text(uiState.qrError, color = Color(0xFFB42318), fontSize = 12.sp)
                }
            }
        }
    }
}

@Composable
private fun QrPayloadImage(payload: String) {
    val model = remember(payload) {
        val encoded = URLEncoder.encode(payload, "UTF-8")
        "https://api.qrserver.com/v1/create-qr-code/?size=360x360&data=$encoded"
    }
    AsyncImage(
        model = model,
        contentDescription = "Attendance QR",
        modifier = Modifier.size(220.dp)
    )
}

@Composable
fun MetricRowCard(label: String, value: String, valueSecondary: String = "", indicatorColor: Color) {
    Card(
        modifier = Modifier.fillMaxWidth(),
        colors = CardDefaults.cardColors(containerColor = Color.White),
        shape = RoundedCornerShape(12.dp),
        elevation = CardDefaults.cardElevation(defaultElevation = 1.dp)
    ) {
        Row(modifier = Modifier.height(IntrinsicSize.Min)) {
            Box(
                modifier = Modifier.width(4.dp).fillMaxHeight()
                    .background(indicatorColor, shape = RoundedCornerShape(topStart = 12.dp, bottomStart = 12.dp))
            )
            Column(modifier = Modifier.padding(16.dp)) {
                Text(label, color = Color(0xFF64748B), fontWeight = FontWeight.Bold, fontSize = 11.sp, letterSpacing = 1.sp)
                Spacer(modifier = Modifier.height(4.dp))
                Row(verticalAlignment = Alignment.Bottom) {
                    Text(value, color = Color(0xFF0F172A), fontWeight = FontWeight.Bold, fontSize = 28.sp)
                    if (valueSecondary.isNotEmpty()) {
                        Text(valueSecondary, color = Color(0xFF64748B), fontWeight = FontWeight.SemiBold, fontSize = 18.sp, modifier = Modifier.padding(bottom = 3.dp))
                    }
                }
            }
        }
    }
}

@Composable
fun StudentAttendanceItem(student: ProfessorStudentStatus, onStatusSelected: (AttendanceStatus) -> Unit) {
    Card(
        modifier = Modifier.fillMaxWidth(),
        colors = CardDefaults.cardColors(containerColor = Color.White),
        shape = RoundedCornerShape(16.dp),
        elevation = CardDefaults.cardElevation(defaultElevation = 0.5.dp)
    ) {
        Row(modifier = Modifier.padding(16.dp), verticalAlignment = Alignment.CenterVertically) {
            Surface(modifier = Modifier.size(48.dp), shape = CircleShape, color = Color(0xFFE2E8F0)) {
                Icon(imageVector = Icons.Default.Person, contentDescription = null, modifier = Modifier.padding(12.dp), tint = Color(0xFF64748B))
            }
            Spacer(modifier = Modifier.width(16.dp))
            Column(modifier = Modifier.weight(1f)) {
                Text(text = student.name, color = Color(0xFF0F172A), fontWeight = FontWeight.Bold, fontSize = 16.sp)
                Text(text = student.details, color = Color(0xFF64748B), fontSize = 12.sp, lineHeight = 16.sp)
            }
        }

        Row(modifier = Modifier.fillMaxWidth().padding(start = 16.dp, end = 16.dp, bottom = 16.dp)) {
            AttendanceSegmentButton("PRESENT", student.status == AttendanceStatus.PRESENT, Color(0xFF1D4ED8), Modifier.weight(1f)) { onStatusSelected(AttendanceStatus.PRESENT) }
            Spacer(modifier = Modifier.width(8.dp))
            AttendanceSegmentButton("ABSENT", student.status == AttendanceStatus.ABSENT, Color(0xFFB91C1C), Modifier.weight(1f)) { onStatusSelected(AttendanceStatus.ABSENT) }
            Spacer(modifier = Modifier.width(8.dp))
            AttendanceSegmentButton("LATE", student.status == AttendanceStatus.LATE, Color(0xFF92400E), Modifier.weight(1f)) { onStatusSelected(AttendanceStatus.LATE) }
        }
    }
}

@Composable
fun AttendanceSegmentButton(
    text: String,
    isSelected: Boolean,
    selectedColor: Color,
    modifier: Modifier = Modifier,
    onClick: () -> Unit
) {
    val bgColor = if (isSelected) selectedColor else Color.White
    val contentColor = if (isSelected) Color.White else Color(0xFF64748B)

    Surface(
        modifier = modifier.height(36.dp).clickable(onClick = onClick),
        shape = RoundedCornerShape(6.dp),
        color = bgColor,
        shadowElevation = if (isSelected) 2.dp else 1.dp
    ) {
        Box(contentAlignment = Alignment.Center, modifier = Modifier.fillMaxSize()) {
            Text(text = text, color = contentColor, fontWeight = FontWeight.Bold, fontSize = 11.sp, letterSpacing = 1.sp)
        }
    }
}

package com.example.minorapp.presentation.screen.attendance

import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableStateOf
import androidx.compose.runtime.setValue
import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.viewModelScope
import com.example.minorapp.BuildConfig
import com.example.minorapp.data.attendance.AttendanceQrSessionData
import com.example.minorapp.data.attendance.BackendProfessorAttendanceRepository
import com.example.minorapp.data.attendance.FinalizeAttendanceQrSessionResult
import com.example.minorapp.data.attendance.FinalizedAttendanceStudentData
import com.example.minorapp.data.attendance.ProfessorCourseData
import com.example.minorapp.data.attendance.ProfessorAttendanceRepository
import com.example.minorapp.data.attendance.ProfessorAttendanceSnapshot
import com.example.minorapp.data.attendance.QrAttendanceRepository
import com.example.minorapp.data.attendance.StartAttendanceQrSessionResult
import com.example.minorapp.data.session.SessionManager
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale
import kotlinx.coroutines.Job
import kotlinx.coroutines.delay
import kotlinx.coroutines.launch

enum class AttendanceStatus { PRESENT, ABSENT, LATE, NONE }
enum class ProfessorAttendanceMode { MANUAL, QR_CODE }

data class ProfessorStudentStatus(
    val studentId: String,
    val name: String,
    val details: String,
    val status: AttendanceStatus = AttendanceStatus.NONE
)

data class ProfessorQrSessionUi(
    val courseId: Long,
    val sessionId: String,
    val timestamp: Long,
    val expiresAtEpochSec: Long,
    val qrPayload: String,
    val secondsRemaining: Int
)

data class ProfessorCourseUi(
    val id: Long,
    val name: String,
    val enrolledCount: Int
)

data class ProfessorAttendanceUiState(
    val profileImageUri: String? = null,
    val courseCode: String = "CS502",
    val titleSubtitle: String = "Advanced Distributed Systems • Lecture Hall B-12",
    val subjectName: String = "Engineering Mathematics",
    val subjectCode: String = "CS-052",
    val sessionDate: String = "Monday, Oct 24",
    val sessionTime: String = "09:00 AM — 10:30 AM",
    val totalEnrolled: Int = 42,
    val markedPresent: Int = 0,
    val completionPercent: Int = 0,
    val basePresentCount: Int = 0,
    val baseMarkedCount: Int = 0,
    val students: List<ProfessorStudentStatus> = emptyList(),
    val attendanceMode: ProfessorAttendanceMode = ProfessorAttendanceMode.MANUAL,
    val selectedCourseId: Long = -1L,
    val availableCourses: List<ProfessorCourseUi> = emptyList(),
    val isStartingQr: Boolean = false,
    val qrSession: ProfessorQrSessionUi? = null,
    val qrError: String? = null,
    val isQrAttendanceFinalized: Boolean = false,
    val qrFinalizedAtText: String? = null,
    val shouldForceReauth: Boolean = false
)

class ProfessorAttendanceViewModel(
    private val sessionManager: SessionManager,
    private val repository: ProfessorAttendanceRepository,
    private val qrAttendanceRepository: QrAttendanceRepository
) : ViewModel() {

    private var qrCountdownJob: Job? = null

    var uiState by mutableStateOf(
        ProfessorAttendanceUiState(profileImageUri = sessionManager.getProfileImageUri())
    )
        private set

    init {
        loadCoursesAndAttendance()
    }

    private fun loadCoursesAndAttendance() {
        viewModelScope.launch {
            val token = sessionManager.getAccessToken()
            val coursesResult = repository.fetchProfessorCourses(token)
            val courses = coursesResult.getOrNull()
            if (courses == null) {
                val message = coursesResult.exceptionOrNull()?.message ?: "Unable to load classes."
                if (isUnauthorizedError(message)) {
                    triggerForcedReauth(message)
                    return@launch
                }
                uiState = uiState.copy(qrError = message)
                return@launch
            }

            if (courses.isEmpty()) {
                uiState = uiState.copy(
                    availableCourses = emptyList(),
                    selectedCourseId = -1L,
                    students = emptyList(),
                    totalEnrolled = 0,
                    qrError = "No class found for this professor."
                )
                return@launch
            }

            val courseUi = courses.map { it.toUi() }
            val initialCourseId = uiState.selectedCourseId.takeIf { selected -> courseUi.any { it.id == selected } }
                ?: courseUi.first().id

            uiState = uiState.copy(
                availableCourses = courseUi,
                selectedCourseId = initialCourseId
            )
            loadRosterForCourse(initialCourseId)
        }
    }

    fun onModeSelected(mode: ProfessorAttendanceMode) {
        uiState = uiState.copy(attendanceMode = mode, qrError = null)
        if (mode == ProfessorAttendanceMode.MANUAL) {
            clearQrSession()
        }
    }

    fun onCourseSelected(courseId: Long) {
        uiState = uiState.copy(selectedCourseId = courseId)
        loadRosterForCourse(courseId)
    }

    fun onStartQrAttendance() {
        if (uiState.selectedCourseId <= 0L) {
            uiState = uiState.copy(qrError = "Select a valid class before starting attendance.")
            return
        }
        viewModelScope.launch {
            uiState = uiState.copy(isStartingQr = true, qrError = null)
            when (
                val result = qrAttendanceRepository.startAttendanceSession(
                    accessToken = sessionManager.getAccessToken(),
                    courseId = uiState.selectedCourseId
                )
            ) {
                is StartAttendanceQrSessionResult.Success -> {
                    applyNewQrSession(result.session)
                }

                is StartAttendanceQrSessionResult.Failure -> {
                    if (isUnauthorizedError(result.message)) {
                        triggerForcedReauth(result.message)
                        return@launch
                    }
                    uiState = uiState.copy(isStartingQr = false, qrError = result.message, qrSession = null)
                }
            }
        }
    }

    fun onForceReauthHandled() {
        uiState = uiState.copy(shouldForceReauth = false)
    }

    fun onStudentStatusChange(studentId: String, newStatus: AttendanceStatus) {
        val updatedList = uiState.students.map {
            if (it.studentId == studentId) it.copy(status = newStatus) else it
        }
        uiState = uiState.copy(students = updatedList)
        updateDerivedMetrics()
    }

    fun onMarkAllPresent() {
        val updatedList = uiState.students.map {
            it.copy(status = AttendanceStatus.PRESENT)
        }
        uiState = uiState.copy(students = updatedList)
        updateDerivedMetrics()
    }

    private fun applyNewQrSession(session: AttendanceQrSessionData) {
        val nowEpoch = System.currentTimeMillis() / 1000
        val initialSeconds = (session.expiresAtEpochSec - nowEpoch).coerceAtLeast(0).toInt()

        uiState = uiState.copy(
            isStartingQr = false,
            qrError = null,
            isQrAttendanceFinalized = false,
            qrFinalizedAtText = null,
            qrSession = ProfessorQrSessionUi(
                courseId = session.courseId,
                sessionId = session.sessionId,
                timestamp = session.timestamp,
                expiresAtEpochSec = session.expiresAtEpochSec,
                qrPayload = session.qrPayload,
                secondsRemaining = initialSeconds
            )
        )

        qrCountdownJob?.cancel()
        qrCountdownJob = viewModelScope.launch {
            while (true) {
                delay(1_000)
                val current = uiState.qrSession ?: break
                if (current.secondsRemaining <= 1) {
                    uiState = uiState.copy(qrSession = null)
                    finalizeExpiredSession(current)
                    break
                }
                uiState = uiState.copy(qrSession = current.copy(secondsRemaining = current.secondsRemaining - 1))
            }
        }
    }

    private suspend fun finalizeExpiredSession(expiredSession: ProfessorQrSessionUi) {
        when (
            val result = qrAttendanceRepository.finalizeAttendanceSession(
                accessToken = sessionManager.getAccessToken(),
                courseId = expiredSession.courseId,
                sessionId = expiredSession.sessionId
            )
        ) {
            is FinalizeAttendanceQrSessionResult.Success -> {
                applyFinalizedStatuses(result.data.students)
                uiState = uiState.copy(
                    qrError = "Session ended. Attendance finalized.",
                    isQrAttendanceFinalized = true,
                    qrFinalizedAtText = formatFinalizedTimestamp(System.currentTimeMillis())
                )
            }

            is FinalizeAttendanceQrSessionResult.Failure -> {
                if (isUnauthorizedError(result.message)) {
                    triggerForcedReauth(result.message)
                    return
                }
                val fallback = uiState.students.map {
                    if (it.status == AttendanceStatus.PRESENT) it else it.copy(status = AttendanceStatus.ABSENT)
                }
                uiState = uiState.copy(
                    students = fallback,
                    qrError = result.message,
                    isQrAttendanceFinalized = true,
                    qrFinalizedAtText = formatFinalizedTimestamp(System.currentTimeMillis())
                )
                updateDerivedMetrics()
            }
        }
    }

    private fun applyFinalizedStatuses(finalStudents: List<FinalizedAttendanceStudentData>) {
        if (finalStudents.isEmpty()) {
            uiState = uiState.copy(qrError = "Session ended, but no enrolled students were returned.")
            return
        }

        val finalized = finalStudents.map { item ->
            ProfessorStudentStatus(
                studentId = item.studentId,
                name = item.name,
                details = item.details,
                status = if (item.status.equals("PRESENT", ignoreCase = true)) AttendanceStatus.PRESENT else AttendanceStatus.ABSENT
            )
        }

        uiState = uiState.copy(
            students = finalized,
            basePresentCount = 0,
            baseMarkedCount = 0,
            totalEnrolled = finalized.size,
            markedPresent = finalized.count { it.status == AttendanceStatus.PRESENT },
            completionPercent = 100
        )
    }

    private fun clearQrSession() {
        qrCountdownJob?.cancel()
        uiState = uiState.copy(qrSession = null)
    }

    private fun loadRosterForCourse(courseId: Long) {
        if (courseId <= 0L) return

        viewModelScope.launch {
            val token = sessionManager.getAccessToken()
            val snapshotResult = repository.fetchAttendanceSnapshot(token, courseId)
            val snapshot = snapshotResult.getOrNull()
            if (snapshot == null) {
                val message = snapshotResult.exceptionOrNull()?.message ?: "Unable to load class roster."
                if (isUnauthorizedError(message)) {
                    triggerForcedReauth(message)
                    return@launch
                }
                uiState = uiState.copy(qrError = message)
                return@launch
            }

            val selected = uiState.selectedCourseId
            val available = uiState.availableCourses
            uiState = snapshot.toUiState(profileImageUri = sessionManager.getProfileImageUri()).copy(
                selectedCourseId = selected,
                availableCourses = available,
                attendanceMode = uiState.attendanceMode,
                isQrAttendanceFinalized = uiState.isQrAttendanceFinalized,
                qrFinalizedAtText = uiState.qrFinalizedAtText
            )
            updateDerivedMetrics()
        }
    }

    private fun formatFinalizedTimestamp(timestampMillis: Long): String {
        val formatter = SimpleDateFormat("dd MMM, hh:mm a", Locale.getDefault())
        return formatter.format(Date(timestampMillis))
    }

    private fun triggerForcedReauth(message: String) {
        sessionManager.clearSession()
        clearQrSession()
        uiState = uiState.copy(
            isStartingQr = false,
            qrError = message,
            shouldForceReauth = true
        )
    }

    private fun isUnauthorizedError(message: String): Boolean {
        val normalized = message.lowercase(Locale.ENGLISH)
        return normalized.contains("unauthorized") || normalized.contains("session expired") || normalized.contains("login again")
    }

    private fun updateDerivedMetrics() {
        val basePresent = uiState.basePresentCount
        val thisListPresent = uiState.students.count { it.status == AttendanceStatus.PRESENT }
        val thisListMarked = uiState.students.count { it.status != AttendanceStatus.NONE }
        val totalEnrolled = uiState.totalEnrolled.coerceAtLeast(1)

        val totalPresent = basePresent + thisListPresent
        val baseMarked = uiState.baseMarkedCount
        val totalMarked = baseMarked + thisListMarked
        val completion = ((totalMarked / totalEnrolled.toDouble()) * 100).toInt()

        uiState = uiState.copy(
            markedPresent = totalPresent,
            completionPercent = completion
        )
    }

    override fun onCleared() {
        qrCountdownJob?.cancel()
        super.onCleared()
    }

    companion object {
        fun factory(sessionManager: SessionManager): ViewModelProvider.Factory =
            object : ViewModelProvider.Factory {
                @Suppress("UNCHECKED_CAST")
                override fun <T : ViewModel> create(modelClass: Class<T>): T {
                    return ProfessorAttendanceViewModel(
                        sessionManager = sessionManager,
                        repository = BackendProfessorAttendanceRepository(BuildConfig.AUTH_BASE_URL),
                        qrAttendanceRepository = QrAttendanceRepository(BuildConfig.AUTH_BASE_URL)
                    ) as T
                }
            }
    }
}

private fun ProfessorAttendanceSnapshot.toUiState(profileImageUri: String?): ProfessorAttendanceUiState {
    val resolvedSubjectName = "Engineering Mathematics"
    val resolvedSubjectCode = subjectCode.trim().ifBlank { "CS - 052" }

    return ProfessorAttendanceUiState(
        profileImageUri = profileImageUri,
        courseCode = courseCode,
        titleSubtitle = titleSubtitle,
        subjectName = resolvedSubjectName,
        subjectCode = resolvedSubjectCode,
        sessionDate = sessionDate,
        sessionTime = sessionTime,
        totalEnrolled = totalEnrolled,
        basePresentCount = basePresentCount,
        baseMarkedCount = baseMarkedCount,
        students = students.mapIndexed { index, student ->
            ProfessorStudentStatus(
                studentId = student.studentId,
                name = student.name,
                details = student.details,
                status = if (index == 0) AttendanceStatus.PRESENT else AttendanceStatus.NONE
            )
        }
    )
}

private fun ProfessorCourseData.toUi(): ProfessorCourseUi {
    return ProfessorCourseUi(id = id, name = name, enrolledCount = enrolledCount)
}

package com.example.minorapp.presentation.screen.attendance

import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableStateOf
import androidx.compose.runtime.setValue
import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.viewModelScope
import com.example.minorapp.BuildConfig
import com.example.minorapp.data.attendance.AttendanceQrSessionData
import com.example.minorapp.data.attendance.BackendProfessorAttendanceRepository
import com.example.minorapp.data.attendance.FinalizeAttendanceQrSessionResult
import com.example.minorapp.data.attendance.FinalizedAttendanceStudentData
import com.example.minorapp.data.attendance.ProfessorCourseData
import com.example.minorapp.data.attendance.ProfessorAttendanceRepository
import com.example.minorapp.data.attendance.ProfessorAttendanceSnapshot
import com.example.minorapp.data.attendance.QrAttendanceRepository
import com.example.minorapp.data.attendance.StartAttendanceQrSessionResult
import com.example.minorapp.data.session.SessionManager
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale
import kotlinx.coroutines.Job
import kotlinx.coroutines.delay
import kotlinx.coroutines.launch
import org.json.JSONArray
import org.json.JSONObject

enum class AttendanceStatus { PRESENT, ABSENT, LATE, NONE }
enum class ProfessorAttendanceMode { MANUAL, QR_CODE }

data class ProfessorStudentStatus(
    val studentId: String,
    val name: String,
    val details: String,
    val status: AttendanceStatus = AttendanceStatus.NONE
)

data class ProfessorQrSessionUi(
    val courseId: Long,
    val sessionId: String,
    val timestamp: Long,
    val expiresAtEpochSec: Long,
    val qrPayload: String,
    val secondsRemaining: Int
)

data class ProfessorCourseUi(
    val id: Long,
    val name: String,
    val enrolledCount: Int
)

data class AttendanceHistoryEntryUi(
    val courseName: String,
    val modeLabel: String,
    val recordedAtText: String
)

data class ProfessorAttendanceUiState(
    val profileImageUri: String? = null,
    val courseCode: String = "CS502",
    val titleSubtitle: String = "Advanced Distributed Systems • Lecture Hall B-12",
    val subjectName: String = "Engineering Mathematics",
    val subjectCode: String = "CS-052",
    val sessionDate: String = "Monday, Oct 24",
    val sessionTime: String = "09:00 AM — 10:30 AM",
    val totalEnrolled: Int = 42,
    val markedPresent: Int = 0,
    val completionPercent: Int = 0,
    val basePresentCount: Int = 0,
    val baseMarkedCount: Int = 0,
    val students: List<ProfessorStudentStatus> = emptyList(),
    val attendanceMode: ProfessorAttendanceMode = ProfessorAttendanceMode.MANUAL,
    val selectedCourseId: Long = -1L,
    val availableCourses: List<ProfessorCourseUi> = emptyList(),
    val isStartingQr: Boolean = false,
    val qrSession: ProfessorQrSessionUi? = null,
    val qrError: String? = null,
    val isQrAttendanceFinalized: Boolean = false,
    val qrFinalizedAtText: String? = null,
    val attendanceHistory: List<AttendanceHistoryEntryUi> = emptyList(),
    val shouldForceReauth: Boolean = false
)

class ProfessorAttendanceViewModel(
    private val sessionManager: SessionManager,
    private val repository: ProfessorAttendanceRepository,
    private val qrAttendanceRepository: QrAttendanceRepository
) : ViewModel() {

    private var qrCountdownJob: Job? = null

    var uiState by mutableStateOf(
        ProfessorAttendanceUiState(profileImageUri = sessionManager.getProfileImageUri())
    )
        private set

    init {
        restoreAttendanceHistory()
        loadCoursesAndAttendance()
    }

    private fun loadCoursesAndAttendance() {
        viewModelScope.launch {
            val token = sessionManager.getAccessToken()
            val coursesResult = repository.fetchProfessorCourses(token)
            val courses = coursesResult.getOrNull()
            if (courses == null) {
                val message = coursesResult.exceptionOrNull()?.message ?: "Unable to load classes."
                if (isUnauthorizedError(message)) {
                    triggerForcedReauth(message)
                    return@launch
                }
                uiState = uiState.copy(qrError = message)
                return@launch
            }

            if (courses.isEmpty()) {
                uiState = uiState.copy(
                    availableCourses = emptyList(),
                    selectedCourseId = -1L,
                    students = emptyList(),
                    totalEnrolled = 0,
                    qrError = "No class found for this professor."
                )
                return@launch
            }

            val courseUi = courses.map { it.toUi() }
            val initialCourseId = uiState.selectedCourseId.takeIf { selected -> courseUi.any { it.id == selected } }
                ?: courseUi.first().id

            uiState = uiState.copy(
                availableCourses = courseUi,
                selectedCourseId = initialCourseId
            )
            loadRosterForCourse(initialCourseId)
        }
    }

    fun onModeSelected(mode: ProfessorAttendanceMode) {
        uiState = uiState.copy(attendanceMode = mode, qrError = null)
        if (mode == ProfessorAttendanceMode.MANUAL) {
            clearQrSession()
        }
    }

    fun onCourseSelected(courseId: Long) {
        uiState = uiState.copy(selectedCourseId = courseId)
        loadRosterForCourse(courseId)
    }

    fun onStartQrAttendance() {
        if (uiState.selectedCourseId <= 0L) {
            uiState = uiState.copy(qrError = "Select a valid class before starting attendance.")
            return
        }
        viewModelScope.launch {
            uiState = uiState.copy(isStartingQr = true, qrError = null)
            when (
                val result = qrAttendanceRepository.startAttendanceSession(
                    accessToken = sessionManager.getAccessToken(),
                    courseId = uiState.selectedCourseId
                )
            ) {
                is StartAttendanceQrSessionResult.Success -> {
                    applyNewQrSession(result.session)
                }

                is StartAttendanceQrSessionResult.Failure -> {
                    if (isUnauthorizedError(result.message)) {
                        triggerForcedReauth(result.message)
                        return@launch
                    }
                    uiState = uiState.copy(isStartingQr = false, qrError = result.message, qrSession = null)
                }
            }
        }
    }

    fun onForceReauthHandled() {
        uiState = uiState.copy(shouldForceReauth = false)
    }

    fun onStudentStatusChange(studentId: String, newStatus: AttendanceStatus) {
        val updatedList = uiState.students.map {
            if (it.studentId == studentId) it.copy(status = newStatus) else it
        }
        uiState = uiState.copy(students = updatedList)
        updateDerivedMetrics()
    }

    fun onMarkAllPresent() {
        val updatedList = uiState.students.map {
            it.copy(status = AttendanceStatus.PRESENT)
        }
        uiState = uiState.copy(students = updatedList)
        updateDerivedMetrics()
    }

    fun onSubmitAttendanceRecord() {
        addAttendanceHistoryEntry(ProfessorAttendanceMode.MANUAL)
    }

    private fun applyNewQrSession(session: AttendanceQrSessionData) {
        val nowEpoch = System.currentTimeMillis() / 1000
        val initialSeconds = (session.expiresAtEpochSec - nowEpoch).coerceAtLeast(0).toInt()

        uiState = uiState.copy(
            isStartingQr = false,
            qrError = null,
            isQrAttendanceFinalized = false,
            qrFinalizedAtText = null,
            qrSession = ProfessorQrSessionUi(
                courseId = session.courseId,
                sessionId = session.sessionId,
                timestamp = session.timestamp,
                expiresAtEpochSec = session.expiresAtEpochSec,
                qrPayload = session.qrPayload,
                secondsRemaining = initialSeconds
            )
        )

        qrCountdownJob?.cancel()
        qrCountdownJob = viewModelScope.launch {
            while (true) {
                delay(1_000)
                val current = uiState.qrSession ?: break
                if (current.secondsRemaining <= 1) {
                    uiState = uiState.copy(qrSession = null)
                    finalizeExpiredSession(current)
                    break
                }
                uiState = uiState.copy(qrSession = current.copy(secondsRemaining = current.secondsRemaining - 1))
            }
        }
    }

    private suspend fun finalizeExpiredSession(expiredSession: ProfessorQrSessionUi) {
        when (
            val result = qrAttendanceRepository.finalizeAttendanceSession(
                accessToken = sessionManager.getAccessToken(),
                courseId = expiredSession.courseId,
                sessionId = expiredSession.sessionId
            )
        ) {
            is FinalizeAttendanceQrSessionResult.Success -> {
                applyFinalizedStatuses(result.data.students)
                uiState = uiState.copy(
                    qrError = "Session ended. Attendance finalized.",
                    isQrAttendanceFinalized = true,
                    qrFinalizedAtText = formatFinalizedTimestamp(System.currentTimeMillis())
                )
                addAttendanceHistoryEntry(ProfessorAttendanceMode.QR_CODE)
            }

            is FinalizeAttendanceQrSessionResult.Failure -> {
                if (isUnauthorizedError(result.message)) {
                    triggerForcedReauth(result.message)
                    return
                }
                val fallback = uiState.students.map {
                    if (it.status == AttendanceStatus.PRESENT) it else it.copy(status = AttendanceStatus.ABSENT)
                }
                uiState = uiState.copy(
                    students = fallback,
                    qrError = result.message,
                    isQrAttendanceFinalized = true,
                    qrFinalizedAtText = formatFinalizedTimestamp(System.currentTimeMillis())
                )
                updateDerivedMetrics()
                addAttendanceHistoryEntry(ProfessorAttendanceMode.QR_CODE)
            }
        }
    }

    private fun applyFinalizedStatuses(finalStudents: List<FinalizedAttendanceStudentData>) {
        if (finalStudents.isEmpty()) {
            uiState = uiState.copy(qrError = "Session ended, but no enrolled students were returned.")
            return
        }

        val finalized = finalStudents.map { item ->
            ProfessorStudentStatus(
                studentId = item.studentId,
                name = item.name,
                details = item.details,
                status = if (item.status.equals("PRESENT", ignoreCase = true)) AttendanceStatus.PRESENT else AttendanceStatus.ABSENT
            )
        }

        uiState = uiState.copy(
            students = finalized,
            basePresentCount = 0,
            baseMarkedCount = 0,
            totalEnrolled = finalized.size,
            markedPresent = finalized.count { it.status == AttendanceStatus.PRESENT },
            completionPercent = 100
        )
    }

    private fun clearQrSession() {
        qrCountdownJob?.cancel()
        uiState = uiState.copy(qrSession = null)
    }

    private fun loadRosterForCourse(courseId: Long) {
        if (courseId <= 0L) return

        viewModelScope.launch {
            val token = sessionManager.getAccessToken()
            val snapshotResult = repository.fetchAttendanceSnapshot(token, courseId)
            val snapshot = snapshotResult.getOrNull()
            if (snapshot == null) {
                val message = snapshotResult.exceptionOrNull()?.message ?: "Unable to load class roster."
                if (isUnauthorizedError(message)) {
                    triggerForcedReauth(message)
                    return@launch
                }
                uiState = uiState.copy(qrError = message)
                return@launch
            }

            val selected = uiState.selectedCourseId
            val available = uiState.availableCourses
            uiState = snapshot.toUiState(profileImageUri = sessionManager.getProfileImageUri()).copy(
                selectedCourseId = selected,
                availableCourses = available,
                attendanceMode = uiState.attendanceMode,
                isQrAttendanceFinalized = uiState.isQrAttendanceFinalized,
                qrFinalizedAtText = uiState.qrFinalizedAtText,
                attendanceHistory = uiState.attendanceHistory
            )
            updateDerivedMetrics()
        }
    }

    private fun formatFinalizedTimestamp(timestampMillis: Long): String {
        val formatter = SimpleDateFormat("dd MMM, hh:mm a", Locale.getDefault())
        return formatter.format(Date(timestampMillis))
    }

    private fun addAttendanceHistoryEntry(mode: ProfessorAttendanceMode) {
        val selectedCourseName = uiState.availableCourses
            .firstOrNull { it.id == uiState.selectedCourseId }
            ?.name
            .orEmpty()
            .ifBlank { uiState.courseCode }

        val recordedAtText = SimpleDateFormat("dd MMM yyyy, hh:mm a", Locale.getDefault())
            .format(Date(System.currentTimeMillis()))

        val entry = AttendanceHistoryEntryUi(
            courseName = selectedCourseName,
            modeLabel = if (mode == ProfessorAttendanceMode.QR_CODE) "QR Code" else "Manual",
            recordedAtText = recordedAtText
        )

        val updatedHistory = (listOf(entry) + uiState.attendanceHistory).take(HISTORY_LIMIT)
        uiState = uiState.copy(attendanceHistory = updatedHistory)
        persistAttendanceHistory(updatedHistory)
    }

    private fun restoreAttendanceHistory() {
        val snapshot = sessionManager.getProfessorAttendanceHistorySnapshot().orEmpty()
        if (snapshot.isBlank()) {
            return
        }

        val parsed = runCatching {
            val array = JSONArray(snapshot)
            buildList {
                for (index in 0 until array.length()) {
                    val item = array.optJSONObject(index) ?: continue
                    val courseName = item.optString(HISTORY_KEY_COURSE_NAME).trim()
                    val modeLabel = item.optString(HISTORY_KEY_MODE_LABEL).trim()
                    val recordedAtText = item.optString(HISTORY_KEY_RECORDED_AT_TEXT).trim()
                    if (courseName.isBlank() || modeLabel.isBlank() || recordedAtText.isBlank()) {
                        continue
                    }
                    add(
                        AttendanceHistoryEntryUi(
                            courseName = courseName,
                            modeLabel = modeLabel,
                            recordedAtText = recordedAtText
                        )
                    )
                }
            }
        }.getOrDefault(emptyList())

        if (parsed.isNotEmpty()) {
            uiState = uiState.copy(attendanceHistory = parsed.take(HISTORY_LIMIT))
        }
    }

    private fun persistAttendanceHistory(history: List<AttendanceHistoryEntryUi>) {
        if (history.isEmpty()) {
            sessionManager.saveProfessorAttendanceHistorySnapshot(null)
            return
        }

        val array = JSONArray()
        history.take(HISTORY_LIMIT).forEach { entry ->
            array.put(
                JSONObject()
                    .put(HISTORY_KEY_COURSE_NAME, entry.courseName)
                    .put(HISTORY_KEY_MODE_LABEL, entry.modeLabel)
                    .put(HISTORY_KEY_RECORDED_AT_TEXT, entry.recordedAtText)
            )
        }
        sessionManager.saveProfessorAttendanceHistorySnapshot(array.toString())
    }

    private fun triggerForcedReauth(message: String) {
        sessionManager.clearSession()
        clearQrSession()
        uiState = uiState.copy(
            isStartingQr = false,
            qrError = message,
            shouldForceReauth = true
        )
    }

    private fun isUnauthorizedError(message: String): Boolean {
        val normalized = message.lowercase(Locale.ENGLISH)
        return normalized.contains("unauthorized") || normalized.contains("session expired") || normalized.contains("login again")
    }

    private fun updateDerivedMetrics() {
        val basePresent = uiState.basePresentCount
        val thisListPresent = uiState.students.count { it.status == AttendanceStatus.PRESENT }
        val thisListMarked = uiState.students.count { it.status != AttendanceStatus.NONE }
        val totalEnrolled = uiState.totalEnrolled.coerceAtLeast(1)

        val totalPresent = basePresent + thisListPresent
        val baseMarked = uiState.baseMarkedCount
        val totalMarked = baseMarked + thisListMarked
        val completion = ((totalMarked / totalEnrolled.toDouble()) * 100).toInt()

        uiState = uiState.copy(
            markedPresent = totalPresent,
            completionPercent = completion
        )
    }

    override fun onCleared() {
        qrCountdownJob?.cancel()
        super.onCleared()
    }

    companion object {
        private const val HISTORY_LIMIT = 10
        private const val HISTORY_KEY_COURSE_NAME = "courseName"
        private const val HISTORY_KEY_MODE_LABEL = "modeLabel"
        private const val HISTORY_KEY_RECORDED_AT_TEXT = "recordedAtText"

        fun factory(sessionManager: SessionManager): ViewModelProvider.Factory =
            object : ViewModelProvider.Factory {
                @Suppress("UNCHECKED_CAST")
                override fun <T : ViewModel> create(modelClass: Class<T>): T {
                    return ProfessorAttendanceViewModel(
                        sessionManager = sessionManager,
                        repository = BackendProfessorAttendanceRepository(BuildConfig.AUTH_BASE_URL),
                        qrAttendanceRepository = QrAttendanceRepository(BuildConfig.AUTH_BASE_URL)
                    ) as T
                }
            }
    }
}

private fun ProfessorAttendanceSnapshot.toUiState(profileImageUri: String?): ProfessorAttendanceUiState {
    val resolvedSubjectName = "Engineering Mathematics"
    val resolvedSubjectCode = subjectCode.trim().ifBlank { "CS - 052" }

    return ProfessorAttendanceUiState(
        profileImageUri = profileImageUri,
        courseCode = courseCode,
        titleSubtitle = titleSubtitle,
        subjectName = resolvedSubjectName,
        subjectCode = resolvedSubjectCode,
        sessionDate = sessionDate,
        sessionTime = sessionTime,
        totalEnrolled = totalEnrolled,
        basePresentCount = basePresentCount,
        baseMarkedCount = baseMarkedCount,
        students = students.mapIndexed { index, student ->
            ProfessorStudentStatus(
                studentId = student.studentId,
                name = student.name,
                details = student.details,
                status = if (index == 0) AttendanceStatus.PRESENT else AttendanceStatus.NONE
            )
        }
    )
}

private fun ProfessorCourseData.toUi(): ProfessorCourseUi {
    return ProfessorCourseUi(id = id, name = name, enrolledCount = enrolledCount)
}
